7	const PROCESSING_FEE = 5;
8	const FIRST_INSURANCE_SURCHARGE = 0.1;
9	const CURSE_SURCHARGE = 0.5;
10	const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
11	const HIGH_ENCHANTMENT_THRESHOLD = 5;
12	const LOYALTY_DISCOUNT = 0.2;
13	const LOYALTY_YEARS_THRESHOLD = 2;
14	const FOLLOWUP_DISCOUNT = 0.15;
15	const COMPONENT_BASE_PREMIUM = 25;
16	const COMPONENT_BLOCK_BASE_PREMIUM = 60;
17	const COMPONENT_BLOCK_SIZE = 3;
18	
19	const MAIN_ITEM_BASE_PREMIUM: Record<string, number> = {
20	  sword: 100,
21	  amulet: 60,
22	};
23	
24	const isMainItem = (item: Item): boolean => item.type in MAIN_ITEM_BASE_PREMIUM;
25	
26	const ceilWithEpsilon = (n: number): number => Math.ceil(Math.round(n * 1e8) / 1e8);
27	
28	const rateAmount = (base: number, applies: boolean, rate: number): number =>
29	  applies ? base * rate : 0;
30	
31	const isHighlyEnchanted = (item: Item): boolean =>
32	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
33	
34	const mainItemBase = (item: Item): number => MAIN_ITEM_BASE_PREMIUM[item.type];
35	
36	const mainItemPremium = (item: Item): number => {
37	  const base = mainItemBase(item);
38	  return (
39	    base +
40	    rateAmount(base, item.cursed === true, CURSE_SURCHARGE) +
41	    rateAmount(base, isHighlyEnchanted(item), HIGH_ENCHANTMENT_SURCHARGE) +
42	    base * FIRST_INSURANCE_SURCHARGE
43	  );
44	};
45	
46	const componentGroupBase = (count: number): number => {
47	  const blocks = Math.floor(count / COMPONENT_BLOCK_SIZE);
48	  const leftover = count % COMPONENT_BLOCK_SIZE;
49	  return blocks * COMPONENT_BLOCK_BASE_PREMIUM + leftover * COMPONENT_BASE_PREMIUM;
50	};
51	
52	const componentCountsByType = (components: Item[]): Map<string, number> => {
53	  const counts = new Map<string, number>();
54	  for (const item of components) {
55	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
56	  }
57	  return counts;
58	};
59	
60	const sumComponentGroupBases = (components: Item[]): number =>
61	  [...componentCountsByType(components).values()].reduce(
62	    (total, count) => total + componentGroupBase(count),
63	    0,
64	  );
65	
66	const sumComponentPremiums = (components: Item[]): number =>
67	  sumComponentGroupBases(components) * (1 + FIRST_INSURANCE_SURCHARGE);
68	
69	const partitionItems = (items: Item[]): { mainItems: Item[]; components: Item[] } => {
70	  const mainItems: Item[] = [];
71	  const components: Item[] = [];
72	  for (const item of items) {
73	    (isMainItem(item) ? mainItems : components).push(item);
74	  }
75	  return { mainItems, components };
76	};
77	
78	const sumMainItemPremiums = (mainItems: Item[]): number =>
79	  mainItems.reduce((sum, item) => sum + mainItemPremium(item), 0);
80	
81	const sumMainItemBases = (mainItems: Item[]): number =>
82	  mainItems.reduce((sum, item) => sum + mainItemBase(item), 0);
83	
84	const isLoyalCustomer = (customer: Customer): boolean =>
85	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD;
86	
87	const priceQuote = (step: QuoteStep, customer: Customer, isFollowUp: boolean): { premium: number } => {
88	  const { mainItems, components } = partitionItems(step.items);
89	  const policyBase = sumMainItemBases(mainItems) + sumComponentGroupBases(components);
90	  const itemsTotal = sumMainItemPremiums(mainItems) + sumComponentPremiums(components);
91	  const loyalty = rateAmount(policyBase, isLoyalCustomer(customer), LOYALTY_DISCOUNT);
92	  const followUp = rateAmount(policyBase, isFollowUp, FOLLOWUP_DISCOUNT);
93	  return { premium: ceilWithEpsilon(itemsTotal - loyalty - followUp + PROCESSING_FEE) };
94	};
95	
96	const countQuotesBefore = (steps: Step[], index: number): number =>
97	  steps.slice(0, index).filter((s) => s.op === "quote").length;
98	
99	export const runScenario = (scenario: Scenario): { results: unknown[] } => ({
100	  results: scenario.steps.map((step, i) =>
101	    priceQuote(step, scenario.customer, countQuotesBefore(scenario.steps, i) > 0),
102	  ),
103	});
