const isLoyalCustomer = (customer: Customer): boolean =>
  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD;

const policyBaseOf = (mainItems: Item[], components: Item[]): number =>
  sumMainItemBases(mainItems) + sumComponentGroupBases(components);

const itemsTotalOf = (mainItems: Item[], components: Item[]): number =>
  sumMainItemPremiums(mainItems) + sumComponentPremiums(components);

const totalDiscount = (policyBase: number, customer: Customer, isFollowUp: boolean): number =>
  rateAmount(policyBase, isLoyalCustomer(customer), LOYALTY_DISCOUNT) +
  rateAmount(policyBase, isFollowUp, FOLLOWUP_DISCOUNT);

const priceQuote = (step: QuoteStep, customer: Customer, isFollowUp: boolean): { premium: number } => {
  const { mainItems, components } = partitionItems(step.items);
  const policyBase = policyBaseOf(mainItems, components);
  const itemsTotal = itemsTotalOf(mainItems, components);
  return {
    premium: ceilWithEpsilon(itemsTotal - totalDiscount(policyBase, customer, isFollowUp) + PROCESSING_FEE),
  };
};
